// ── Helpers ──────────────────────────────────────────────────────────────────

function fmt$(val) {
  if (val == null) return '--';
  const n = Number(val);
  if (isNaN(n)) return '--';
  const abs = Math.abs(n);
  const str = abs >= 1000
    ? new Intl.NumberFormat('en-US', { style: 'currency', currency: 'USD', minimumFractionDigits: 0, maximumFractionDigits: 0 }).format(abs)
    : new Intl.NumberFormat('en-US', { style: 'currency', currency: 'USD', minimumFractionDigits: 2, maximumFractionDigits: 2 }).format(abs);
  return n < 0 ? `-${str}` : str;
}

function fmtPct(val) {
  if (val == null) return '--';
  return `${Number(val) >= 0 ? '+' : ''}${Number(val).toFixed(2)}%`;
}

function timeAgo(ts) {
  if (!ts) return 'never';
  const ms = typeof ts === 'number' && ts < 1e12 ? ts * 1000 : new Date(ts).getTime();
  if (isNaN(ms)) return '--';
  const diff = Date.now() - ms;
  const secs = Math.floor(diff / 1000);
  if (secs < 5) return 'just now';
  if (secs < 60) return `${secs}s ago`;
  const mins = Math.floor(secs / 60);
  if (mins < 60) return `${mins}m ago`;
  const hrs = Math.floor(mins / 60);
  if (hrs < 24) return `${hrs}h ago`;
  return `${Math.floor(hrs / 24)}d ago`;
}

function fmtDatetime(ts) {
  if (!ts) return '--';
  try {
    const ms = typeof ts === 'number' && ts < 1e12 ? ts * 1000 : new Date(ts).getTime();
    return new Date(ms).toLocaleString('en-US', {
      month: 'short', day: 'numeric', hour: '2-digit', minute: '2-digit', second: '2-digit',
    });
  } catch { return '--'; }
}

function pnlColor(val) {
  const n = Number(val);
  if (isNaN(n)) return C.textSecondary;
  return n >= 0 ? C.green : C.red;
}

